import machine
import time
from umqtt.simple import MQTTClient

# Initialize temperature sensor (example: DS18B20)
rom = [0x28, 0xFF, 0x7F, 0x4D, 0xB9, 0x16, 0x35, 0x0C]
ds_sensor = machine.OneWire(machine.Pin(4))
ds_sensor.convert_temp()

def read_temperature():
    ds_sensor.convert_temp()
    time.sleep_ms(750)
    return ds_sensor.read_temp()

# MQTT broker details
client_id = b'micropython_client'
broker_ip = b'192.168.1.100'

# Create MQTT client instance
client = MQTTClient(client_id, broker_ip)

def publish_temperature():
    while True:
        temp = read_temperature()
        client.connect()
        client.publish(b'sensors/temp', str(temp).encode())
        client.disconnect()
        time.sleep(60)  # Publish every minute

publish_temperature()